 */
function solve(n) {
    // Function to reverse the digits of a number
    function reverseNumber(num) {
        return parseInt(String(num).split('').reverse().join(''));
    }

    const r = reverseNumber(n);

    const minVal = Math.min(n, r);
    const maxVal = Math.max(n, r);

    // Sieve of Eratosthenes to find primes up to maxVal
    // Since maxVal <= 1000, a simple sieve or trial division up to 1000 is efficient enough.
    const isPrime = new Array(maxVal + 1).fill(true);
